const Q_BIOLOGY_2020_MODEL_I=[{"id": "objective>Biology>2020-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Below is a List of the levels of organization in organisms. <br/> i. Tissue <br/>  ii. System <br/>  iii. Cell  <br/> iV. organ <br/> The correct sequence of the levels in an increasing order of complexity is? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> I,II,III,IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">  lll, I, lV, ll</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> lll, IV, l, ll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">  lV, lll, I, ll</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of the levels of organization in organisms in increasing order of complexity is Cell, Tissue, Organ, System. This is because cells combine to form tissues, tissues combine to form organs, and organs work together in systems. Therefore, the correct answer is 'lll, I, lV, ll'.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2020-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organelles is used for locomotion in Paramecium? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">  pseudopodium <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Trichocyst </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Cilium  <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">  pellicle </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium uses cilia for locomotion. Cilia are small, hair-like structures covering the surface of the paramecium. They beat in coordinated waves, allowing the paramecium to move in water. Therefore, the correct answer is 'Cilium'.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2020-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following constitutes the main internal tissue of a leaf?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cuticle <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Mesophyll <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vascular tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lower epidermis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main internal tissue of a leaf is the mesophyll. The mesophyll is the primary location of photosynthesis in the plant. It is located between the upper and lower epidermis, which are the outer layers of the leaf. The mesophyll is made up of two types of tissues: the palisade parenchyma, which is located directly beneath the upper epidermis and is where most photosynthesis occurs, and the spongy parenchyma, which is located beneath the palisade parenchyma and has many air spaces for gas exchange.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2020-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">which of the following statements best explains the term aestivation? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a device for survival during a period of extreme food and water shortage <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A method of survival adopted by plants during dry season <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Movement of animals over long distance <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A method of survival adopted by animals under favourable condition <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It is a survival strategy used by many invertebrates, like snails and crustaceans, and by some mammals, like the North American desert tortoise, to survive the hottest and driest part of the year. It is a device for survival during a period of extreme food and water shortage.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2020-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes will not introduce carbon dioxide into the atmosphere?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Breathing <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Respiration <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Putrefaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis is a process used by plants and other organisms to convert light energy, usually from the Sun, into chemical energy that can be later released to fuel the organisms' activities. This chemical energy is stored in carbohydrate molecules, such as sugars, which are synthesized from carbon dioxide and water. Hence, photosynthesis does not introduce carbon dioxide into the atmosphere, instead it uses carbon dioxide from the atmosphere.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS~~RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2020-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The large intercellular air spaces which penetrate the tissues of most hydrophytes provide a  <br/>  pathway through which? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbondioxide absorbed by leaves can diffuse to the roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen produced in the leaves can diffuse to the submerged parts\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salts absorbed by roots can reach other parts of the plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plant hormones are transported to various parts</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The large intercellular air spaces in hydrophytes, also known as aerenchyma, provide a pathway for oxygen produced in the leaves during photosynthesis to diffuse to the submerged parts of the plant. This is crucial for the survival of hydrophytes in waterlogged conditions where oxygen is limited.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2020-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory that new organs or characteristics develop in organisms when there is a need for them was postulated by <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Charles Darwin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jean Lamarck</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Gregor Mendel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wallace</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory that new organs or characteristics develop in organisms when there is a need for them is known as Lamarckism, postulated by Jean-Baptiste Lamarck. This theory is also known as the 'use and disuse theory' or 'inheritance of acquired characteristics'.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2020-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The inability of some individuals to perceive the taste of some substances is an example of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">individual adaptation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physiological variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphological variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphological adaptation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The inability of some individuals to perceive the taste of some substances is an example of physiological variation. Physiological variations are differences in the function of organisms, which can be influenced by genetic factors, environmental conditions, or a combination of both.</div>", "topic": "VARIATION IN POPULATION : PHYSIOLOGICAL VARIATION"}, {"id": "objective>Biology>2020-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term afforestation is used in describing <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">harvesting of natural forest resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planting trees of value to man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fallowing of forestland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">felling of trees in the forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Afforestation refers to the process of planting trees, or sowing seeds, in a barren land devoid of any trees to create a forest. The term is often used to mean reforestation, which is the process of restoring (replanting) forests that have been cut or destroyed.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2020-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Group instinct or social behaviour is not displayed in? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soldier ants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chickens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weaver birds</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group instinct or social behaviour is a characteristic of animals that live in groups and display a level of organization and cooperation. This is seen in animals like soldier ants, bees, and weaver birds. Chickens, on the other hand, do not display this level of social behaviour.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2020-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents the phenotypic ratio, when a plant Rr is crossed with another plant Rr, assuming that the gene R for round seed is dominant and wrinkled r is recessive? <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a heterozygous plant (Rr) is crossed with another heterozygous plant (Rr), the phenotypic ratio is typically 3:1. This is based on Mendel's law of segregation, which states that during the formation of gametes, the two traits carried by each parent separate. In this case, 3 out of 4 plants will have round seeds (dominant trait) and 1 out of 4 will have wrinkled seeds (recessive trait).</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2020-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All hereditary characters in a cell are passed on from parent-cell to daughter-cell through the process of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meiosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">implantation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitosis is the process by which a cell duplicates its DNA and divides to create two identical daughter cells. This process ensures that all genetic information is accurately passed from the parent cell to the daughter cells. Meiosis is a type of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell, as in the production of gametes and plant spores. Fertilization and implantation are processes related to sexual reproduction, not the transmission of genetic information from parent cell to daughter cell.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2020-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The evidence for evolution can be obtained from the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fossil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anatomy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">history</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embryology</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Evidence for evolution can be obtained from fossils, comparative anatomy, and embryology. Fossils provide a record of species that lived long ago, and can show both gradual change in species over time and the pattern of speciation. Comparative anatomy can show similarities in structures among different species, suggesting a common ancestor. Embryology can show similarities in the development of embryos in different species, also suggesting a common ancestor. History, however, is not a source of evidence for biological evolution.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2020-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following methods of reproduction is common to Paramecium and Amoeba? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conjugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sexual reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Binary fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Budding</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both Paramecium and Amoeba reproduce asexually through a process known as binary fission. In this process, the organism duplicates its genetic material and then divides into two equal or nearly equal parts, each of which becomes an independent organism. Conjugation is a form of sexual reproduction that is found in some species of Paramecium, but not in Amoeba. Budding is a form of asexual reproduction that is not found in either Paramecium or Amoeba.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2020-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cup-shaped part of the Bowman's capsule contains <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nephridium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glomerulus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loop of Henle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nephron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Bowman's capsule is a cup-like sac at the beginning of the tubular component of a nephron in the mammalian kidney that performs the first step in the filtration of blood to form urine. The glomerulus is a tuft of capillaries located within the Bowman's capsule. The glomerulus filters the blood and the filtrate is collected in the Bowman's capsule. Therefore, the cup-shaped part of the Bowman's capsule contains the glomerulus.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2020-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The condition known as cretinism is caused by the deficiency of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adrenalin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vitamin A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thyroxin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cretinism is a condition of severely stunted physical and mental growth due to untreated congenital deficiency of thyroid hormones (hypothyroidism). Thyroxin is a hormone the thyroid gland secretes into the bloodstream. Once in the bloodstream, thyroxin helps regulate metabolism (the process by which the body turns food into energy). It also plays a role in bone growth and the development of the brain and nervous system in children. Therefore, the deficiency of thyroxin causes cretinism.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2020-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The brain and spinal cord make up the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">peripheral nervous system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">automatic nervous system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">central nervous-system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">somatic nervous system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The central nervous system (CNS) is the part of the nervous system consisting primarily of the brain and spinal cord. The CNS is so named because it integrates the received information and coordinates and influences the activity of all parts of the bodies of bilaterally symmetric animals—i.e., all multicellular animals except sponges and radially symmetric animals such as jellyfish. Therefore, the brain and spinal cord make up the central nervous system.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2020-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following parts of the mammalian brain is involved in taking the decision to run rather than walk? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Medulla oblongata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cerebrum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mid brain</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebrum is the part of the brain that is involved in taking the decision to run rather than walk. It is responsible for voluntary actions, decision making, and cognitive functions. The cerebellum is involved in motor control and coordination, the medulla oblongata controls autonomic functions like breathing and heart rate, and the midbrain is involved in vision, hearing, motor control, sleep and wake cycles.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2020-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following parts of the' tongue does not correspond to the taste indicated  <br/> against it? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tip-sweet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Centre salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Back-sour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Side-sour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The back of the tongue is associated with the taste of bitterness, not sourness. The tip of the tongue is indeed associated with sweetness, the sides with sourness, and the center with saltiness.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2020-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the difference between viviparous and oviparous animals? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Possession of yolked eggs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laying of unfertilized eggs\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laying and brooding of eggs <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protection of eggs from predator</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between viviparous and oviparous animals is the method of development of the young ones. Viviparous animals give birth to live young ones while oviparous animals lay eggs that develop and hatch outside the mother's body. Laying and brooding of eggs</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2020-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ located in the mammalian abdominal cavity just below the diaphragm <br/> and lying on top of the stomach is the <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bladder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intestine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organ located in the mammalian abdominal cavity just below the diaphragm and lying on top of the stomach is the liver. The liver is a large, meaty organ that sits on the right side of the belly. It is protected by the rib cage. The liver has two large sections, called the right and the left lobes.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2020-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reagents is used for the test for starch? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Million's reagent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's' solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iodine solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iodine solution is used for the test for starch. When iodine solution is mixed with starch, it turns from brown to dark blue. This is a chemical reaction that indicates the presence of starch. The other reagents listed are used for testing other substances: Million's reagent for proteins, Fehling's solution for reducing sugars, and Sudan III for lipids.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2020-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is least relevant as a factor affecting organisms in an aquatic environment?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Soil pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water clarity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Strength of currents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Availability of sunlight</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil pH is more significant in terrestrial ecosystems where plants grow in direct contact with soil. In aquatic environments, factors like water clarity (related to turbidity), strength of currents or waves, and sunlight availability directly influence the survival of aquatic organisms. </div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2020-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All these are examples of sustainable management of natural resources except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Banning the use of fishing nets with very small mesh sizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preserving wetlands as bird habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allowing mining without environmental control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Recycling materials like paper and metal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mining without environmental regulations can cause soil erosion, water pollution, and habitat destruction. The other measures listed promote sustainability and help maintain natural resources for future generations.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2020-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water rises most rapidly in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy-loam soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loamy soil</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water rises most rapidly in sandy soil. This is due to the large pore spaces between the sand particles which allow water to move through the soil quickly. Clayey soil, sandy-loam soil, and loamy soil have smaller pore spaces and therefore water moves through them more slowly. Therefore, the correct answer is 'sandy soil'.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2020-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Thrombocytes are blood cells responsible for initiating <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phagocytosis of bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synthesis of ribosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clotting of the blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">immunity to certain infectious diseases</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thrombocytes, also known as platelets, are blood cells responsible for initiating the clotting of the blood. They do this by sticking together to form a plug at the site of an injured blood vessel. This helps to prevent excessive bleeding. Therefore, the correct answer is 'clotting of the blood'.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2020-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When gametes from pure breeding parents with contrasting features such as tallness and  <br/> shortness are involved in monohybrid cross, the offspring in the first filial generation are usually <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pure breed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heterozygous dominant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homozygous recessive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutants</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a monohybrid cross involving pure breeding parents with contrasting traits, the offspring in the first filial generation (F1) are usually heterozygous dominant. This is because each parent contributes one allele to the offspring, and in this case, one parent contributes a dominant allele (for tallness) and the other contributes a recessive allele (for shortness). The dominant allele masks the effect of the recessive allele, resulting in a heterozygous dominant offspring.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2020-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive radiation as illustrated by the variety of forms in insects can be regarded as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">behavioral modification\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a case of rapid population growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a physiological process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an evidence of evolution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive radiation refers to the process by which species evolve from a single ancestral species into a variety of forms that are each adapted to a specific environment. This is considered evidence of evolution because it demonstrates how species can diversify and adapt to different environments over time.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2020-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Muscles are attached to bones by means of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ligament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cartilage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synovial membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tendons</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Muscles are attached to bones by means of tendons. Tendons are tough bands of fibrous connective tissue that connect muscle to bone and are capable of withstanding tension. Ligaments, on the other hand, connect bone to bone, and cartilage provides a smooth surface for joint movement. The synovial membrane is the lining of the joint capsule that secretes synovial fluid for lubrication.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2020-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle which eliminate water from the body of protozoa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plasma membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protoplasm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle which eliminates water from the body of protozoa is the contractile vacuole. This organelle functions to pump water out of the cell to prevent the cell from bursting due to osmotic pressure. The other options listed do not perform this function.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2020-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Natality is a factor affecting population density because it involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in population due to immigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in population due to emigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of mature females in the population\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of all young ones produced in the population <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natality refers to the birth rate in a population, which directly affects population density. It involves the number of all young ones produced in the population. The other options listed, such as immigration and emigration, are factors that affect population density but they are not directly related to natality.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2020-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wing of a bat and that of a bird, the flippers of a whale and the fins of s fish are example of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adaptive radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vestigial structures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convergent evolution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wing of a bat and that of a bird, the flippers of a whale and the fins of a fish are examples of convergent evolution. Convergent evolution is a process in which organisms that are not closely related independently evolve similar traits as a result of having to adapt to similar environments or ecological niches. The other options listed do not accurately describe this phenomenon.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2020-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of individuals in a habitat in relation to the unit space available to each organism is referred to as the <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of individuals in a habitat in relation to the unit space available to each organism is referred to as the density. This is a fundamental concept in ecology, where it is used to quantify the distribution of organisms in a habitat. The other options, birth rate, mortality, and frequency, do not accurately describe this concept.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2020-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra is regarded as a multicellular plant because <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its cells are linked together by cytoplasmic strands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its cells are joined to form organs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cylindrical cells are linked end to end</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the filaments consist of one cell only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra is regarded as a multicellular plant because its cells are linked together by cytoplasmic strands. This allows for communication and transport of nutrients between cells. The other options do not accurately describe why Spirogyra is considered multicellular.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2020-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the loss of water vapour through the stomata is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perspiration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration is the process by which plants lose water vapour through small openings in their leaves called stomata. This process helps in cooling the plant, maintaining nutrient flow, and enabling water movement from roots to leaves. Respiration is the release of energy from glucose, photosynthesis is food production using sunlight, and perspiration refers to sweating in animals, not plants.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2020-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following would be the primary producer in a food chain? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Saprophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Herbivores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carnivores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green plants</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, the primary producer is always an organism that can produce its own food. This is usually done through photosynthesis, a process where light energy from the sun is converted into chemical energy in the form of glucose. Green plants are capable of photosynthesis, making them the primary producers in a food chain. Saprophytes, herbivores, and carnivores are all consumers, not producers.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2020-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Cat <br/> II. Frog <br/> III. bird <br/> IV. Fish <br/> Oviparity is the type of fertilization that is not exhibited by the organism labelled <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oviparity is a mode of reproduction in animals in which embryos develop inside eggs that are laid externally. This is common among birds, reptiles, and some fishes. Among the options given, cat does not exhibit oviparity.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2020-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Blood is pumped into the right ventricle by the contraction of the auricle wall through? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tricuspid valve, or right atrioventricular valve, is on the right side of the mammalian heart, at the upper part of the right ventricle. The function of the valve is to prevent back flow (regurgitation) of blood from the right ventricle into the right atrium/auricle during right ventricular contraction. <br/> </div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2020-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a part of the mammalian skeleton . use it to answer this question. <br/> The function of the part labelled I is to <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide support to the spinal cord</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide surface for attachment of the muscle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carry the spinal cord</div>", "<div style=\"font-family:Cambria;font-size:17px;\">articulate with adjacent vertebrae</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled 1 is the Cervical Vertebral(Neural) Canal. The bony cervical vertebral canal serves as a protective conduit for the spinal cord and as an exit point of the cervical nerve roots. Because of the bulging of the cervical neuromeres as well as the other fibers that must traverse the cervical vertebral canal to reach the lower portions of the body, the cervical spinal cord occupies a significantly greater proportion of the space available in the spinal canal relative to the space occupied by the thoracic and lumbar spinal cord.  <br/> </div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2020-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram, the organs for attachments to the lining of the host's intestine are labelled <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II is the hook, while III is the sucker . <br/> Tapeworms attach themselves to the inner lining of the definitive host's small intestine. They don't have mouths to hold on with, but they have an arrangement of suckers and hooks that lets them latch on and bury their heads in the intestinal lining. When a worm is in place, the host's partially digested food flows over him, and the tapeworm absorbs necessary nutrients through his skin. If the parasite steals enough food from the host, the animal may begin to show signs of illness or other problems. <br/> </div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}];
